extra.modelCss:
/* Variáveis + tema claro/escuro */

:root {
  --bg: #ffffff;
  --panel: #f3f4f6;
  --text: #111827;
  --muted: #6b7280;
  --accent: #2563eb;
  --border: rgba(17, 24, 39, 0.12);
  --radius: 14px;
}

html[data-theme="dark"] {
  --bg: #0b0f19;
  --panel: #111827;
  --text: #e5e7eb;
  --muted: #9ca3af;
  --accent: #60a5fa;
  --border: rgba(255, 255, 255, 0.10);
}

body {
  background: var(--bg);
  color: var(--text);
}

.card {
  background: var(--panel);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 16px;
}

a {
  color: var(--accent);
}

.muted {
  color: var(--muted);
}
